options.customCss:
:root {
  /* Brand Colors - Ghoroya Bengali Restaurant */
  --chat--color--primary: #d9480f;
  --chat--color--primary-shade-50: #c2410c;
  --chat--color--primary--shade-100: #9a3412;

  --chat--color--secondary: #f59e0b;
  --chat--color-secondary-shade-50: #d97706;

  --chat--color-white: #ffffff;
  --chat--color-light: #fff7ed;
  --chat--color-light-shade-50: #fed7aa;
  --chat--color-light-shade-100: #fdba74;
  --chat--color-medium: #f3d2a2;
  --chat--color-dark: #1c1917;
  --chat--color-disabled: #d6d3d1;
  --chat--color-typing: #7c2d12;

  /* Base Layout */
  --chat--spacing: 1rem;
  --chat--border-radius: 1.25rem;
  --chat--transition-duration: 0.25s;
  --chat--font-family: Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;

  /* Window */
  --chat--window--width: 430px;
  --chat--window--height: 680px;
  --chat--window--bottom: 1.25rem;
  --chat--window--right: 1.25rem;
  --chat--window--z-index: 9999;
  --chat--window--border: 1px solid rgba(255, 255, 255, 0.35);
  --chat--window--border-radius: 1.5rem;
  --chat--window--margin-bottom: 1rem;

  /* Header */
  --chat--header-height: auto;
  --chat--header--padding: 1.25rem;
  --chat--header--background: linear-gradient(135deg, #7c2d12 0%, #d9480f 55%, #f59e0b 100%);
  --chat--header--color: #fffaf0;
  --chat--header--border-top: none;
  --chat--header--border-bottom: 1px solid rgba(255, 255, 255, 0.18);
  --chat--header--border-left: none;
  --chat--header--border-right: none;

  --chat--heading--font-size: 1.65rem;
  --chat--subtitle--font-size: 0.9rem;
  --chat--subtitle--line-height: 1.5;

  /* Messages */
  --chat--message--font-size: 0.95rem;
  --chat--message--padding: 0.9rem 1rem;
  --chat--message--border-radius: 1.1rem;
  --chat--message-line-height: 1.55;
  --chat--message--margin-bottom: 0.85rem;

  --chat--message--bot--background: rgba(255, 255, 255, 0.92);
  --chat--message--bot--color: #292524;
  --chat--message--bot--border: 1px solid rgba(214, 211, 209, 0.65);

  --chat--message--user--background: linear-gradient(135deg, #d9480f, #f59e0b);
  --chat--message--user--color: #fffaf0;
  --chat--message--user--border: none;

  --chat--message--pre--background: rgba(124, 45, 18, 0.08);
  --chat--messages-list--padding: 1rem;

  /* Toggle Button */
  --chat--toggle--size: 68px;
  --chat--toggle--width: 68px;
  --chat--toggle--height: 68px;
  --chat--toggle--border-radius: 999px;
  --chat--toggle--background: linear-gradient(135deg, #d9480f, #f59e0b);
  --chat--toggle--hover--background: linear-gradient(135deg, #c2410c, #d97706);
  --chat--toggle--active--background: #9a3412;
  --chat--toggle--color: #ffffff;

  /* Input */
  --chat--textarea--height: 54px;
  --chat--textarea--max-height: 14rem;
  --chat--input--font-size: 0.95rem;
  --chat--input--border: 1px solid rgba(214, 211, 209, 0.75);
  --chat--input--border-radius: 1rem;
  --chat--input--padding: 0.85rem 1rem;
  --chat--input--background: rgba(255, 255, 255, 0.96);
  --chat--input--text-color: #1c1917;
  --chat--input--line-height: 1.45;
  --chat--input--placeholder--font-size: 0.9rem;
  --chat--input--border-active: 1px solid #f59e0b;
  --chat--input--left--panel--width: 2.25rem;

  /* Buttons */
  --chat--button--padding: 0.7rem 1rem;
  --chat--button--border-radius: 999px;
  --chat--button--font-size: 0.95rem;
  --chat--button--line-height: 1;

  --chat--button--color--primary: #fffaf0;
  --chat--button--background--primary: linear-gradient(135deg, #d9480f, #f59e0b);
  --chat--button--border--primary: none;
  --chat--button--color--primary--hover: #fffaf0;
  --chat--button--background--primary--hover: linear-gradient(135deg, #c2410c, #d97706);
  --chat--button--border--primary--hover: none;

  --chat--button--color--primary--disabled: #fff7ed;
  --chat--button--background--primary--disabled: #fed7aa;
  --chat--button--border--primary--disabled: none;

  --chat--button--color--secondary: #fffaf0;
  --chat--button--background--secondary: #78716c;
  --chat--button--border--secondary: none;
  --chat--button--color--secondary--hover: #fffaf0;
  --chat--button--background--secondary--hover: #57534e;
  --chat--button--border--secondary--hover: none;

  --chat--close--button--color-hover: #fed7aa;

  /* Send and File Buttons */
  --chat--input--send--button--background: transparent;
  --chat--input--send--button--color: #d9480f;
  --chat--input--send--button--background-hover: rgba(245, 158, 11, 0.15);
  --chat--input--send--button--color-hover: #9a3412;

  --chat--input--file--button--background: transparent;
  --chat--input--file--button--color: #d9480f;
  --chat--input--file--button--background-hover: rgba(245, 158, 11, 0.15);
  --chat--input--file--button--color-hover: #9a3412;

  --chat--files-spacing: 0.35rem;

  /* Body and Footer */
  --chat--body--background:
    radial-gradient(circle at top left, rgba(245, 158, 11, 0.22), transparent 32%),
    linear-gradient(180deg, #fff7ed 0%, #ffedd5 100%);
  --chat--footer--background: rgba(255, 247, 237, 0.92);
  --chat--footer--color: #1c1917;
}

/* Modern glass window effect */
.chat-window {
  box-shadow:
    0 24px 80px rgba(124, 45, 18, 0.28),
    0 8px 24px rgba(0, 0, 0, 0.12);
  backdrop-filter: blur(18px);
  overflow: hidden;
}

/* Better readable bubbles */
.chat-message {
  max-width: 78%;
  box-shadow: 0 8px 24px rgba(28, 25, 23, 0.08);
}

/* User message alignment polish */
.chat-message-from-user,
.chat-message.user {
  border-bottom-right-radius: 0.35rem;
}

/* Bot message polish */
.chat-message-from-bot,
.chat-message.bot {
  border-bottom-left-radius: 0.35rem;
}

/* Toggle button glow */
.chat-window-toggle,
.chat-toggle {
  box-shadow:
    0 12px 28px rgba(217, 72, 15, 0.38),
    0 0 0 6px rgba(245, 158, 11, 0.12);
  transition: transform 0.25s ease, box-shadow 0.25s ease;
}

.chat-window-toggle:hover,
.chat-toggle:hover {
  transform: translateY(-3px) scale(1.03);
  box-shadow:
    0 18px 36px rgba(217, 72, 15, 0.45),
    0 0 0 8px rgba(245, 158, 11, 0.16);
}

/* Input area polish */
.chat-input,
.chat-footer textarea,
textarea {
  box-shadow: 0 8px 24px rgba(28, 25, 23, 0.06);
}

/* Mobile friendly */
@media (max-width: 520px) {
  :root {
    --chat--window--width: calc(100vw - 1rem);
    --chat--window--height: calc(100vh - 1rem);
    --chat--window--bottom: 0.5rem;
    --chat--window--right: 0.5rem;
    --chat--window--border-radius: 1.25rem;
  }

  .chat-message {
    max-width: 86%;
  }
}
